#include <bits/stdc++.h>
using namespace std;
int main(){int n,m;cin>>n>>m;vector<string>g(n);for(auto&s:g)cin>>s;vector<vector<int>>d(n,vector<int>(m,0));queue<pair<int,int>>q;q.push({0,0});d[0][0]=1;int dx[]={0,0,1,-1},dy[]={1,-1,0,0};while(!q.empty()){auto[x,y]=q.front();q.pop();for(int k=0;k<4;k++){int nx=x+dx[k],ny=y+dy[k];if(nx<0||ny<0||nx>=n||ny>=m)continue;if(g[nx][ny]=='1'&&d[nx][ny]==0){d[nx][ny]=d[x][y]+1;q.push({nx,ny});}}}cout<<d[n-1][m-1]<<"\n";}
